import React, { createContext, useState, useContext, useEffect } from 'react';
import { guestLogin } from '../api';
import { initSocket, disconnectSocket } from '../socket';

const AuthContext = createContext();

export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(() => {
    const savedUser = localStorage.getItem('vibeUser');
    return savedUser ? JSON.parse(savedUser) : null;
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  useEffect(() => {
    if (user) {
      initSocket(user._id);
    }
  }, [user]);

  const login = async (nickname, gender) => {
    setLoading(true);
    setError(null);
    try {
      const userData = await guestLogin(nickname, gender);
      setUser(userData);
      localStorage.setItem('vibeUser', JSON.stringify(userData));
      initSocket(userData._id);
      return userData;
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed');
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('vibeUser');
    disconnectSocket();
  };

  const updateUser = (userData) => {
    setUser(userData);
    localStorage.setItem('vibeUser', JSON.stringify(userData));
  };

  return (
    <AuthContext.Provider value={{ user, setUser: updateUser, login, logout, loading, error }}>
      {children}
    </AuthContext.Provider>
  );
};

export default AuthContext;
